    for word in sentence.lower().split():
        counts[word] = counts.get(word, 0) + 1
    return counts
```

```python
def sort_by_value(d):
    return dict(sorted(d.items(), key=lambda item: item[1]))
```

```python
def factorial(n):
    if n == 0 or n == 1:
        return 1
    return n * factorial(n - 1)
```

```python
def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True
```

